mapper.update:
update sys_miner_exchange_log
wag_amount = #{wagAmount}, rate = #{rate}, target_currency = #{targetCurrency}, target_amount = #{targetAmount}, status = #{status}, error_msg = #{errorMsg}, update_time = now(),
where exchange_id = #{exchangeId}

mapper.select:
select exchange_id, user_id, request_no, wag_amount, rate, target_currency, target_amount, status, error_msg, create_time, update_time
from sys_miner_exchange_log

    and user_id = #{userId}
    and status = #{status}
    and request_no = #{requestNo}

order by exchange_id desc
